import{_ as s,c as i,o as a,aj as t}from"./chunks/framework.guNMSiFm.js";const c=JSON.parse('{"title":"Keys for Network Deployment","description":"","frontmatter":{},"headers":[],"relativePath":"guide/configure/keys-for-network-deployment.md","filePath":"guide/configure/keys-for-network-deployment.md","lastUpdated":1777621302000}'),n={name:"guide/configure/keys-for-network-deployment.md"};function r(l,e,o,h,p,d){return a(),i("div",null,[...e[0]||(e[0]=[t('<h1 id="keys-for-network-deployment" tabindex="-1">Keys for Network Deployment <a class="header-anchor" href="#keys-for-network-deployment" aria-label="Permalink to &quot;Keys for Network Deployment&quot;">​</a></h1><p>Every network needs distinct key material for clients, peers, genesis signing, and, for NPoS or Nexus profiles, BLS validator identities.</p><h2 id="where-keys-are-used" tabindex="-1">Where Keys Are Used <a class="header-anchor" href="#where-keys-are-used" aria-label="Permalink to &quot;Where Keys Are Used&quot;">​</a></h2><ul><li>Client signing keys are stored in <code>client.toml</code> under <code>[account]</code>.</li><li>Peer identity keys are stored in each peer <code>config.toml</code> as <code>public_key</code> and <code>private_key</code>.</li><li>Peer discovery uses each peer&#39;s public key in <code>trusted_peers</code>.</li><li>BLS validator Proofs-of-Possession are stored in <code>trusted_peers_pop</code> for NPoS profiles.</li><li>Genesis signing uses the <code>[genesis].public_key</code> in peer config and the matching private key when signing the manifest.</li></ul><p>For local or test deployments, let Kagami generate all of these files together:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cargo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --bin</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> kagami</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> localnet</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --build-line</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> iroha3</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --peers</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 4</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --out-dir</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./localnet</span></span></code></pre></div><p>For an existing network or profile, use the guided flow:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cargo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --bin</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> kagami</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> wizard</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --profile</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nexus</span></span></code></pre></div><h2 id="generate-individual-key-pairs" tabindex="-1">Generate Individual Key Pairs <a class="header-anchor" href="#generate-individual-key-pairs" aria-label="Permalink to &quot;Generate Individual Key Pairs&quot;">​</a></h2><p>Use <code>kagami keys</code> for standalone key material:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cargo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --bin</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> kagami</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> keys</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --algorithm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ed25519</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --json</span></span></code></pre></div><p>For BLS validator material, include a Proof-of-Possession:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cargo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --bin</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> kagami</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> keys</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --algorithm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> bls_normal</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --pop</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --json</span></span></code></pre></div><p>Use <code>--seed</code> only for reproducible development fixtures. For production deployment, generate fresh keys and store private keys outside the repository.</p><h2 id="peer-consistency" tabindex="-1">Peer Consistency <a class="header-anchor" href="#peer-consistency" aria-label="Permalink to &quot;Peer Consistency&quot;">​</a></h2><p>All validators must agree on the same genesis transaction, topology, trusted peer public keys, and validator PoPs. A single missing or mismatched peer key can prevent the network from starting or reaching consensus.</p><p>For a minimum Byzantine-fault-tolerant deployment, use at least four peers. Each peer must have its own private key, but every peer configuration needs the same trusted peer set.</p><h2 id="client-accounts" tabindex="-1">Client Accounts <a class="header-anchor" href="#client-accounts" aria-label="Permalink to &quot;Client Accounts&quot;">​</a></h2><p>The client account in <code>client.toml</code> must already exist on-chain. It can be registered by the genesis manifest or by a later transaction. Avoid using the genesis signing identity as a long-lived application account; genesis privileges only apply during the genesis round, and production clients should use their own accounts and roles.</p>',19)])])}const g=s(n,[["render",r]]);export{c as __pageData,g as default};
